import{_ as e,o as a,c as i,a2 as n}from"./chunks/framework.Bix3-HpO.js";const u=JSON.parse('{"title":"Scheduling","description":"DinOdds Scheduling","frontmatter":{"title":"Scheduling","description":"DinOdds Scheduling","weight":80,"extra":{"order":80},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/dinodds/scheduling"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/dinodds/scheduling"}],["meta",{"property":"og:title","content":"Scheduling"}],["meta",{"property":"og:description","content":"DinOdds Scheduling"}],["meta",{"name":"twitter:title","content":"Scheduling"}],["meta",{"name":"twitter:description","content":"DinOdds Scheduling"}]]},"headers":[],"relativePath":"docs/dinodds/scheduling.md","filePath":"docs/dinodds/scheduling.md"}'),t={name:"docs/dinodds/scheduling.md"};function o(l,s,d,r,h,p){return a(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="scheduling" tabindex="-1">Scheduling <a class="header-anchor" href="#scheduling" aria-label="Permalink to &quot;Scheduling&quot;">​</a></h1><p>Find out how the feed updates work and how to set up cron jobs.</p><h2 id="about-scheduling" tabindex="-1">About scheduling <a class="header-anchor" href="#about-scheduling" aria-label="Permalink to &quot;About scheduling&quot;">​</a></h2><p>In order to display the latest odds feeds, your website needs to pull the data from DinoFeeds API periodically. This is done by DinOdds plugin automatically. However, there are some caveats we&#39;ll discuss below.</p><p>But before that, let&#39;s define cron and cron jobs:</p><blockquote><p><strong>Cron</strong> is used to schedule commands or scripts (tasks) on Linux servers at a specified time and date.</p></blockquote><blockquote><p>A <strong>cron job</strong> is the task itself.</p></blockquote><p>For example, I can use cron to schedule a database backup on my server every day at 8:00AM - this would be a cron job. Another example could be deleting temporary files, etc.</p><h3 id="wordpress-cron-jobs" tabindex="-1">WordPress Cron Jobs <a class="header-anchor" href="#wordpress-cron-jobs" aria-label="Permalink to &quot;WordPress Cron Jobs&quot;">​</a></h3><p>WordPress has its own &quot;cron system&quot; called WP-Cron:</p><blockquote><p>WP-Cron is how WordPress handles scheduling time-based tasks in WordPress. Several WordPress core features, such as checking for updates and publishing scheduled post, utilize WP-Cron.</p></blockquote><p>It is a workaround developed by WordPress and it has some very useful features, however it is run on every page load and <strong>only when a page load occurs</strong>.</p><p>This is the main issue that we&#39;re concerned about now. This means that WP-Cron won&#39;t run if there&#39;s no page load. For example, if your plugin has a scheduled feeds update task at 3:00PM and there&#39;s no page load until 3:40PM, feeds won&#39;t be updated by then.</p><p>First of all, I wouldn&#39;t like to rely on a page visit to update my feeds, also it may take a while and delay the page load. There might be other issues as well.</p><p>Ok, to solve this, we need to:</p><ol><li>disable WP-Cron</li><li>use system cron jobs to periodically call WP-Cron</li></ol><p>This ensures that no matter what WP-Cron will be called periodically and WP scheduled tasks will run on time. One of those tasks is updating the feeds.</p><h3 id="disable-wp-cron" tabindex="-1">Disable WP-Cron <a class="header-anchor" href="#disable-wp-cron" aria-label="Permalink to &quot;Disable WP-Cron&quot;">​</a></h3><p>To do this, open your <code>wp-config.php</code> file (it is in your website&#39;s root directory), add the following line and save it. And we&#39;re done here, WP-Cron is disabled.</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;?</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">php</span></span>
<span class="line"></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">define</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">( </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;DISABLE_WP_CRON&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> );</span></span></code></pre></div><p>Make sure you add the line before <code>/* That&#39;s all, stop editing! Happy blogging. */</code> line.</p><h3 id="set-up-system-cron-jobs" tabindex="-1">Set up System Cron Jobs <a class="header-anchor" href="#set-up-system-cron-jobs" aria-label="Permalink to &quot;Set up System Cron Jobs&quot;">​</a></h3><p>So, we need to schedule a command that will ping our website and call WP-Cron periodically. You can choose whatever frequency you want, I suggest one hour and that&#39;s what I use.</p><h4 id="command" tabindex="-1">Command: <a class="header-anchor" href="#command" aria-label="Permalink to &quot;Command:&quot;">​</a></h4><p>Here&#39;s the command that we need to schedule:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wget</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --delete-after</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://MYDOMAIN.com/wp-cron.php</span></span></code></pre></div><p>Make sure to replace <code>MYDOMAIN.com</code> with your actual domain name.</p><p>You can set up cron jobs:</p><ul><li>using a user interface provided by your host</li><li>using command line</li></ul><h4 id="using-user-interface" tabindex="-1">Using user interface <a class="header-anchor" href="#using-user-interface" aria-label="Permalink to &quot;Using user interface&quot;">​</a></h4><p>Usually hosts provide a user interface for scheduling tasks and they usually are called <strong>Cron Jobs</strong>. In your hosting control panel look for cron jobs or scheduler and follow the instructions on how to set them up. In most cases you&#39;ll have to select a frequency and paste the command.</p><p>If you&#39;re having difficulties finding or scheduling tasks on a particular system, a Google search like this &quot;how to create cron jobs in cpanel&quot; may help.</p><h4 id="using-command-line" tabindex="-1">Using command line <a class="header-anchor" href="#using-command-line" aria-label="Permalink to &quot;Using command line&quot;">​</a></h4><p>You&#39;ll need <code>ssh</code> access and some knowledge about using the command line. If you&#39;re not comfortable with it, I&#39;d suggest you either use a visual interface if available or contact your host to assist you.</p><p>Steps:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># connect to server, if prompted with a password, enter it</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> USER@HOST</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># open cron editor</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># if this is the first time you run crontab edit command</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># you may be prompted to select en editor</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">crontab</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># go to the end of the file and paste the command</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> *</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> *</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> *</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> *</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wget</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --delete-after</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://MYDOMAIN.com/wp-cron.php</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># this will run the command at :00 minute every hour</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># you can change 0 to a different number (&lt; 60)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># to run it every 30 minutes, use this</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/30 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> wget --delete-after https://MYDOMAIN.com/wp-cron.php</span></span></code></pre></div><p>Make sure to replace <code>MYDOMAIN.com</code> with your actual domain name.</p><p>And that&#39;s all. Now your WordPress scheduled tasks will run at the frequency you defined regardless of page loads.</p>`,38)])])}const k=e(t,[["render",o]]);export{u as __pageData,k as default};
